import sys
from collections import defaultdict

class UnionFind:
    def __init__(self, size):
        self.parent = list(range(size))
        self.rank = [0] * size
        self.count = size

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        x_root = self.find(x)
        y_root = self.find(y)
        if x_root == y_root:
            return
        if self.rank[x_root] < self.rank[y_root]:
            self.parent[x_root] = y_root
        else:
            self.parent[y_root] = x_root
            if self.rank[x_root] == self.rank[y_root]:
                self.rank[x_root] += 1
        self.count -= 1

def solve(n: int, edges: list[list[int]], k: int) -> int:
    if k == 1:
        return 0
    if n < k:
        return -1  # though problem says k <= n, so this shouldn't happen

    edges_sorted = sorted(edges, key=lambda x: x[2])
    uf = UnionFind(n)
    res = 0

    for u, v, t in edges_sorted:
        if uf.count < k:
            break
        if uf.find(u) != uf.find(v):
            uf.union(u, v)
            res = t

    if uf.count >= k:
        return 0
    else:
        return res
